import React, { useState } from 'react';
import {
  Button,
  Input,
  Modal,
  Select, dispatchAppToast,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { systemService } from '../../../services/system/systemService';
import type {
  LedgerKind,
  UpdateVoucherRegistryDto,
  UpdateVoucherRegistryProcessingLevelDto,
  VoucherRegistryDto,
  VoucherRegistryProcessingLevelDto,
} from '../../../services/system/voucherRegistryModels';
import {
  LEDGER_KIND_LABEL,
  LEDGER_KIND_OPTIONS,
  formatEnabledLevels,
} from '../../../services/system/voucherRegistryModels';
import { mergeProcessingLevels } from '../../../services/system/processingLevelModels';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'system-voucher-setup-registry';

type FormErrors = Partial<Record<'name' | 'processingLevels', string>>;

const toFormLevels = (rows: VoucherRegistryProcessingLevelDto[]): UpdateVoucherRegistryProcessingLevelDto[] =>
  rows.map(r => ({
    level: r.level,
    isEnabled: r.isEnabled,
    isDefault: r.isDefault,
  }));

const mergeRegistryLevels = (
  ledgerKind: LedgerKind,
  fromApi: VoucherRegistryProcessingLevelDto[],
): VoucherRegistryProcessingLevelDto[] => {
  const byLevel = new Map(fromApi.map(r => [r.level, r]));
  const names = mergeProcessingLevels(ledgerKind, fromApi.map(r => ({
    level: r.level,
    name: r.name,
  })));
  return names.map(n => {
    const existing = byLevel.get(n.level);
    return {
      level: n.level,
      name: n.name,
      isEnabled: existing?.isEnabled ?? false,
      isDefault: existing?.isDefault ?? false,
    };
  });
};

export const VoucherRegistryTab: React.FC = () => {
  const dispatch = useAppDispatch();
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<VoucherRegistryDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<VoucherRegistryDto | null>(null);
  const [form, setForm] = useState<UpdateVoucherRegistryDto>({
    name: '',
    nameEn: '',
    ledgerKind: 'Accounting',
    sortOrder: 0,
    isActive: true,
    processingLevels: [],
  });
  const [levelRows, setLevelRows] = useState<VoucherRegistryProcessingLevelDto[]>([]);
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);

  const handleSearch = () => setSearch(searchDraft.trim());
  const refresh = () => setReloadKey(k => k + 1);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      systemService.getVoucherRegistry()
        .then(data => { if (!cancelled) setItems(data); })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: err instanceof Error ? err.message : 'Lỗi tải đăng ký chứng từ',
              type: 'error',
            });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [reloadKey, dispatch]);

  const filtered = React.useMemo(() => {
    const q = search.trim().toLowerCase();
    if (!q) return items;
    return items.filter(
      r =>
        r.voucherTypeCode.toLowerCase().includes(q)
        || r.name.toLowerCase().includes(q),
    );
  }, [items, search]);

  const reloadLevelNames = async (ledgerKind: LedgerKind, current: VoucherRegistryProcessingLevelDto[]) => {
    const configs = await systemService.getProcessingLevels(ledgerKind);
    const merged = mergeRegistryLevels(
      ledgerKind,
      current.map(r => ({
        ...r,
        name: configs.find(c => c.level === r.level)?.name ?? r.name,
      })),
    );
    setLevelRows(merged);
    setForm(f => ({ ...f, processingLevels: toFormLevels(merged) }));
  };

  const openEdit = (row: VoucherRegistryDto) => {
    setEditing(row);
    const levels = mergeRegistryLevels(row.ledgerKind, row.processingLevels);
    setLevelRows(levels);
    setForm({
      name: row.name,
      nameEn: row.nameEn ?? '',
      ledgerKind: row.ledgerKind,
      sortOrder: row.sortOrder,
      isActive: row.isActive,
      processingLevels: toFormLevels(levels),
    });
    setErrors({});
    setModalOpen(true);
  };

  const handleLedgerKindChange = async (ledgerKind: LedgerKind) => {
    setForm(f => ({ ...f, ledgerKind }));
    try {
      await reloadLevelNames(ledgerKind, levelRows.map(r => ({ ...r, isEnabled: false, isDefault: false })));
    } catch {
      dispatchAppToast(dispatch, { message: 'Lỗi tải tên mức xử lý', type: 'error' });
    }
  };

  const toggleEnabled = (level: number, enabled: boolean) => {
    setLevelRows(prev => {
      const next = prev.map(r => {
        if (r.level !== level) return r;
        return { ...r, isEnabled: enabled, isDefault: enabled ? r.isDefault : false };
      });
      if (!enabled) {
        const stillDefault = next.some(r => r.isDefault);
        if (!stillDefault) {
          const firstEnabled = next.find(r => r.isEnabled);
          if (firstEnabled) firstEnabled.isDefault = true;
        }
      }
      setForm(f => ({ ...f, processingLevels: toFormLevels(next) }));
      return next;
    });
    setErrors(prev => ({ ...prev, processingLevels: undefined }));
  };

  const setDefaultLevel = (level: number) => {
    setLevelRows(prev => {
      const next = prev.map(r => ({
        ...r,
        isDefault: r.level === level,
        isEnabled: r.level === level ? true : r.isEnabled,
      }));
      setForm(f => ({ ...f, processingLevels: toFormLevels(next) }));
      return next;
    });
    setErrors(prev => ({ ...prev, processingLevels: undefined }));
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!form.name?.trim()) next.name = 'Nhập tên chứng từ';
    const enabled = levelRows.filter(r => r.isEnabled);
    if (enabled.length === 0) next.processingLevels = 'Chọn ít nhất một mức xử lý';
    else if (enabled.filter(r => r.isDefault).length !== 1) {
      next.processingLevels = 'Chọn đúng một mức mặc định';
    }
    return next;
  };

  const handleSave = async () => {
    if (!editing) return;
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      await systemService.updateVoucherRegistry(editing.voucherTypeCode, {
        ...form,
        name: form.name.trim(),
        nameEn: form.nameEn?.trim() || undefined,
        processingLevels: toFormLevels(levelRows),
      });
      dispatchAppToast(dispatch, { message: 'Cập nhật đăng ký chứng từ thành công', type: 'success' });
      setModalOpen(false);
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: err instanceof Error ? err.message : 'Lưu thất bại',
        type: 'error',
      });
    } finally {
      setSaving(false);
    }
  };

  return (
    <>
      <p className={styles.subtitle} style={{ marginBottom: 12 }}>
        Loại chứng từ do hệ thống đăng ký sẵn. Cấu hình loại sổ và chọn mức xử lý áp dụng cho từng chứng từ (dropdown trên form/list ERP lấy từ đây). Prefix mã cấu hình ở tab Định dạng mã.
      </p>

      <div className={styles.filtersBar} data-testid={`${TEST_ID}-filters`}>
        <div className={styles.field} data-testid={`${TEST_ID}-field-search`}>
          <Input
            placeholder="Tìm mã, tên..."
            value={searchDraft}
            onChange={e => setSearchDraft(e.target.value)}
            onKeyDown={e => { if (e.key === 'Enter') handleSearch(); }}
          />
        </div>
        <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={handleSearch} onRefresh={refresh} />
      </div>

      <div className={styles.tableCard}>
        {loading ? (
          <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
        ) : filtered.length === 0 ? (
          <div className={styles.empty}>
            <i className="fas fa-inbox" />
            <p>{search.trim() ? 'Không tìm thấy chứng từ phù hợp' : 'Chưa có đăng ký — chạy /setup-voucher-registry'}</p>
          </div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Mã</th>
                  <th>Tên</th>
                  <th>Loại sổ</th>
                  <th>Mức XL</th>
                  <th>Mặc định</th>
                  <th>Stt</th>
                  <th>Trạng thái</th>
                  <th className={styles.colActions} />
                </tr>
              </thead>
              <tbody>
                {filtered.map(r => (
                  <tr key={r.voucherTypeCode}>
                    <td className={styles.masterCodeNameCell}><code>{r.voucherTypeCode}</code></td>
                    <td>{r.name}</td>
                    <td>{LEDGER_KIND_LABEL[r.ledgerKind] ?? r.ledgerKind}</td>
                    <td>{formatEnabledLevels(r)}</td>
                    <td>{r.defaultProcessingLevel ?? '—'}</td>
                    <td>{r.sortOrder}</td>
                    <td>{r.isActive ? 'Đang dùng' : 'Ẩn'}</td>
                    <td className={styles.colActions}>
                      <button
                        type="button"
                        className={styles.actionBtn}
                        onClick={() => openEdit(r)}
                        title="Sửa đăng ký"
                        data-testid={`${TEST_ID}-edit-${r.voucherTypeCode}`}
                      >
                        <i className="fas fa-edit" />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      <Modal isOpen={modalOpen} onClose={() => setModalOpen(false)} title="Sửa đăng ký chứng từ" size="lg">
        <div data-testid={`${TEST_ID}-modal-form`}>
          {editing && (
            <>
              <div className={styles.formGrid}>
                <div className={styles.masterCodeNameRow}>
                  <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                    <Input label="Mã loại CT" value={editing.voucherTypeCode} disabled fullWidth />
                  </div>
                  <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                    <Input
                      label="Tên chứng từ"
                      required
                      value={form.name}
                      onChange={e => {
                        setErrors(prev => ({ ...prev, name: undefined }));
                        setForm(f => ({ ...f, name: e.target.value }));
                      }}
                      error={errors.name}
                      fullWidth
                    />
                  </div>
                </div>
                <div className={styles.field}>
                  <Input
                    label="Tên tiếng Anh"
                    value={form.nameEn ?? ''}
                    onChange={e => setForm(f => ({ ...f, nameEn: e.target.value }))}
                    fullWidth
                  />
                </div>
                <div className={styles.field} data-testid={`${TEST_ID}-field-ledgerKind`}>
                  <Select
                    label="Loại sổ"
                    required
                    value={form.ledgerKind}
                    onChange={e => { handleLedgerKindChange(e.target.value as LedgerKind); }}
                    options={[...LEDGER_KIND_OPTIONS]}
                    fullWidth
                  />
                </div>
                <div className={styles.field}>
                  <Input
                    label="Thứ tự hiển thị"
                    type="number"
                    value={String(form.sortOrder ?? 0)}
                    onChange={e => {
                      const raw = e.target.value;
                      const next = raw === '' ? 0 : Number(raw);
                      setForm(f => ({ ...f, sortOrder: Number.isFinite(next) ? Math.trunc(next) : 0 }));
                    }}
                    fullWidth
                  />
                </div>
                <div className={styles.field}>
                  <Select
                    label="Trạng thái"
                    value={form.isActive ? 'true' : 'false'}
                    onChange={e => setForm(f => ({ ...f, isActive: e.target.value === 'true' }))}
                    options={[
                      { value: 'true', label: 'Đang dùng' },
                      { value: 'false', label: 'Ẩn' },
                    ]}
                    fullWidth
                  />
                </div>
              </div>

              <div style={{ marginTop: 16 }} data-testid={`${TEST_ID}-processing-levels`}>
                <div className={styles.label} style={{ marginBottom: 8, fontWeight: 600 }}>
                  Mức xử lý áp dụng
                  {errors.processingLevels && (
                    <span style={{ color: 'var(--ds-color-error, #C33A00)', marginLeft: 8, fontWeight: 400 }}>
                      {errors.processingLevels}
                    </span>
                  )}
                </div>
                <div className={styles.tableWrapper}>
                  <table className={styles.table}>
                    <thead>
                      <tr>
                        <th style={{ width: 56 }}>Mức</th>
                        <th>Tên (Tab 3)</th>
                        <th style={{ width: 88 }}>Sử dụng</th>
                        <th style={{ width: 88 }}>Mặc định</th>
                      </tr>
                    </thead>
                    <tbody>
                      {levelRows.map(r => (
                        <tr key={r.level}>
                          <td><strong>{r.level}</strong></td>
                          <td>{r.name || `Mức ${r.level}`}</td>
                          <td>
                            <input
                              type="checkbox"
                              checked={r.isEnabled}
                              onChange={e => toggleEnabled(r.level, e.target.checked)}
                              data-testid={`${TEST_ID}-level-${r.level}-enabled`}
                              aria-label={`Sử dụng mức ${r.level}`}
                            />
                          </td>
                          <td>
                            <input
                              type="radio"
                              name={`${TEST_ID}-default-level`}
                              checked={r.isDefault}
                              disabled={!r.isEnabled}
                              onChange={() => setDefaultLevel(r.level)}
                              data-testid={`${TEST_ID}-level-${r.level}-default`}
                              aria-label={`Mặc định mức ${r.level}`}
                            />
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>

              <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end', marginTop: 16 }}>
                <Button variant="secondary" onClick={() => setModalOpen(false)} data-testid={`${TEST_ID}-cancel-btn`}>
                  Hủy
                </Button>
                <Button
                  variant="primary"
                  onClick={handleSave}
                  disabled={saving}
                  data-testid={`${TEST_ID}-save-btn`}
                >
                  {saving ? 'Đang lưu...' : 'Lưu'}
                </Button>
              </div>
            </>
          )}
        </div>
      </Modal>
    </>
  );
};

export default VoucherRegistryTab;
