export type LedgerKind = 'Accounting' | 'Warehouse';

export interface VoucherRegistryProcessingLevelDto {
  level: number;
  name: string;
  isEnabled: boolean;
  isDefault: boolean;
}

export interface VoucherRegistryDto {
  voucherTypeCode: string;
  name: string;
  nameEn?: string;
  ledgerKind: LedgerKind;
  idCodePrefix: string;
  sortOrder: number;
  isActive: boolean;
  defaultProcessingLevel?: string;
  processingLevels: VoucherRegistryProcessingLevelDto[];
}

export interface UpdateVoucherRegistryProcessingLevelDto {
  level: number;
  isEnabled: boolean;
  isDefault: boolean;
}

export interface UpdateVoucherRegistryDto {
  name: string;
  nameEn?: string;
  ledgerKind: LedgerKind;
  sortOrder: number;
  isActive: boolean;
  processingLevels: UpdateVoucherRegistryProcessingLevelDto[];
}

export const LEDGER_KIND_OPTIONS = [
  { value: 'Accounting', label: 'Sổ kế toán (tiền)' },
  { value: 'Warehouse', label: 'Sổ kho' },
] as const;

export const LEDGER_KIND_LABEL: Record<LedgerKind, string> = {
  Accounting: 'Sổ kế toán',
  Warehouse: 'Sổ kho',
};

export function formatEnabledLevels(row: VoucherRegistryDto): string {
  return row.processingLevels
    .filter(l => l.isEnabled)
    .map(l => l.level)
    .join(', ') || '—';
}
